function playPrevious(mode) {
    if (mergedSubtitles.length === 0) return;

    infiniteRepeatMode = null; // 이전으로 갈 때도 무한 반복 모드 해제

    if (currentIndex <= 0) {
        currentIndex = 0;
        alert("첫 번째 문장입니다.");
        if (typeof resumeVoiceRecognition === 'function') { // 음성 명령으로 호출된 경우를 위해
            resumeVoiceRecognition();
        }
        return;
    }

    currentIndex--;
    isStudying = true; 
    saveProgress(currentIndex);

    const sub = mergedSubtitles[currentIndex];

    document.querySelectorAll('.subtitle-item').forEach(el => el.classList.remove('active'));
    const activeItem = document.querySelector(`.subtitle-item[data-index="${currentIndex}"]`);
    if (activeItem) {
        activeItem.classList.add('active');
    }

    scrollListToActive();

    koTextDisplay.textContent = sub.ko || '(내용 없음)';
    enTextDisplay.textContent = sub.en || '(매칭된 영어 자막 없음)';
    koTextDisplay.classList.remove('hidden-text');
    enTextDisplay.classList.remove('hidden-text');

    if (mode === 'ko') {
        if(sub.en) enTextDisplay.classList.add('hidden-text');
        speak(sub.ko, 'ko-KR');
    } else {
        if(sub.ko) koTextDisplay.classList.add('hidden-text');
        speak(sub.en, 'en-US');
    }
}

koSpeakBtn.addEventListener('click', () => playCurrentOrNext('ko'));
